template <class Abel>

struct UnionFind {

    vector<int> par;

    vector<int> rank;

    vector<int> size;

    vector<Abel> diff_weight;



    UnionFind(int n = 1, Abel SUM_UNITY = 0) {

        init(n, SUM_UNITY);

    }



    void init(int n = 1, Abel SUM_UNITY = 0) {

        par.resize(n);

        rank.resize(n);

        size.resize(n);

        diff_weight.resize(n);

        for (int i = 0; i < n; ++i)

            par[i] = i, rank[i] = 0, size[i] = 1, diff_weight[i] = SUM_UNITY;

    }



    int root(int x) {

        if (par[x] == x) {

            return x;

        } else {

            int r = root(par[x]);

            diff_weight[x] += diff_weight[par[x]]; // path compression

            return par[x] = r;

        }

    }

    // returns size of connected-tree number

    int get_size(int x) {

        return size[root(x)];

    }



    Abel weight(int x) {

        root(x);

        return diff_weight[x];

    }



    bool is_same(int x, int y) {

        return root(x) == root(y);

    }



    bool merge(int x, int y, Abel w) {

        w += weight(x);

        w -= weight(y);

        x = root(x);

        y = root(y);

        if (x == y) return false;

        if (rank[x] < rank[y]) swap(x, y), w = -w;

        if (rank[x] == rank[y]) ++rank[x];

        par[y] = x;

        size[x] = size[y] = size[x] + size[y];

        diff_weight[y] = w;

        return true;

    }



    Abel diff(int x, int y) {

        return weight(y) - weight(x);

    }

};

long long fac[MAX_N], finv[MAX_N], inv[MAX_N];

// テーブルを作る前処理 from: https://qiita.com/drken/items/3b4fdf0a78e7a138cd9a

void COMinit() {

    fac[0] = fac[1] = 1;

    finv[0] = finv[1] = 1;

    inv[1] = 1;

    for (int i = 2; i < MAX_N; i++) {

        fac[i] = fac[i - 1] * i % MOD;

        inv[i] = MOD - inv[MOD % i] * (MOD / i) % MOD;

        finv[i] = finv[i - 1] * inv[i] % MOD;

    }

}

// 二項係数計算

long long COM(int n, int k) {

    if (n < k) return 0;

    if (n < 0 || k < 0) return 0;

    return fac[n] * (finv[k] * finv[n - k] % MOD) % MOD;

}

// factorial

long long fact(int n) {

    if (n == 1) return fac[n] = 1;

    if (fac[n]) return fac[n];

    return fac[n] = (fact(n - 1) * n) % MOD;

}



long long gcd(long long a, long long b) {

    if (b == 0) return a;

    return gcd(b, a % b);

}



long long lcm(long long a, long long b) {

    return a / gcd(a, b) * b;

}



long long modpow(long long m, long long p) {

    if (p == 0) return 1;

    if (p % 2)

        return m * modpow(m, p - 1);

    else {

        long res = modpow(m, p / 2);

        return res * res;

    }

}

// Z-algorithm: O(n)

// 文字列が与えられた時、各 i について「S と S[i..|S|-1] の最長共通接頭辞の長さ」を記録した配列 A を O(|S|) で構築するアルゴリズム

// https://snuke.hatenablog.com/entry/2014/12/03/214243

void Z_algorithm(string S, vi &A) {

    A[0] = S.size();

    int i = 1, j = 0;

    while (i < S.size()) {

        while (i + j < S.size() && S[j] == S[i + j])

            ++j;

        A[i] = j;

        if (j == 0) {

            ++i;

            continue;

        }

        int k = 1;

        while (i + k < S.size() && k + A[k] < j)

            A[i + k] = A[k], ++k;

        i += k;

        j -= k;

    }

}

int main() {

    int n;

    string s;

    cin >> n >> s;

    int m = 0;

    rep(i, n) {

        string sub = s.substr(i);

        vector<int> A(n - i, 0);

        Z_algorithm(sub, A);

        rep(j, n - i) {

            if (j >= A[j]) chmax(m, A[j]);

        }

    }

    out(m);

}

