        have[s[i]-'a']=false;

    }



    for(int i=0;i<26;++i){

        if(have[i]){

            printf("-1\n");return 0;

        }

    }



    long long ans = 1,now=0;

    for(int i=0;i<tlen;){

        auto np = lower_bound(pos[t[i]-'a'].begin(),

                              pos[t[i]-'a'].end(),now%slen);

        if(np==pos[t[i]-'a'].end()){

            now = (now/slen+1)*slen;continue;

        }

        now = now/slen*slen+*np;

        if(now>=ans){

            ans=now+1;++i;++now;continue;

        }

        ++i;++now;

    }

    printf("%lld\n",ans);

    return 0;

}
